+fn distributed_bind_host(bind_addr: &str) -> String {
+    let trimmed = bind_addr.trim();
+    if trimmed.is_empty() {
+        return String::new();
+    }
+    if let Ok(addr) = trimmed.parse::<std::net::SocketAddr>() {
+        return addr.ip().to_string();
+    }
+    if let Some(stripped) = trimmed.strip_prefix('[') {
